customCSS:
/* Phi Hash Reactor — Black & Red Reactor Core */
@import url('https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@400;500;600;700&family=Inter:wght@300;400;500;600&family=Fira+Code&display=swap');

.cyber-glow {
  background:
    radial-gradient(ellipse 700px 500px at 20% 0%, rgba(255, 26, 26, 0.22), transparent),
    radial-gradient(ellipse 500px 400px at 80% 100%, rgba(204, 17, 51, 0.14), transparent),
    radial-gradient(ellipse 400px 300px at 50% 50%, rgba(255, 119, 0, 0.06), transparent);
}

.cyber-particles { display: none; }

.cyber-scanlines {
  background: repeating-linear-gradient(
    0deg,
    transparent,
    transparent 2px,
    rgba(255, 26, 26, 0.03) 2px,
    rgba(255, 26, 26, 0.03) 4px
  );
}

.stat-card {
  border: 1px solid rgba(255, 26, 26, 0.12);
  backdrop-filter: blur(10px);
}

.stat-card::before {
  background: linear-gradient(90deg, #ff1a1a, #ff5500);
  height: 2px;
}

.stat-card:hover {
  border-color: rgba(255, 85, 85, 0.28);
  box-shadow: 0 4px 30px rgba(255, 26, 26, 0.15), 0 0 60px rgba(204, 0, 34, 0.08);
}

.stat-value {
  text-shadow: 0 0 20px rgba(255, 26, 26, 0.6);
}

.celebration-title {
  background: linear-gradient(135deg, #ff1a1a, #ff5500);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  text-shadow: none;
  filter: drop-shadow(0 0 20px rgba(255, 26, 26, 0.5));
}

.miner-card, .health-card, .lifetime-card {
  border: 1px solid rgba(255, 26, 26, 0.08);
}

.miner-card:hover {
  border-color: rgba(255, 85, 85, 0.22);
  box-shadow: 0 4px 20px rgba(255, 26, 26, 0.10);
}

.logo {
  color: #ff1a1a;
  text-shadow: 0 0 15px rgba(255, 26, 26, 0.5);
}

/* Reactor pulse on block found */
@keyframes reactorPulse {
  0%   { box-shadow: 0 0 0px rgba(255, 26, 26, 0); }
  50%  { box-shadow: 0 0 40px rgba(255, 26, 26, 0.4), 0 0 80px rgba(204, 0, 34, 0.2); }
  100% { box-shadow: 0 0 0px rgba(255, 26, 26, 0); }
}

.block-found-flash {
  animation: reactorPulse 1.2s ease-in-out;
}
